window.__QUIZ_DATA__=[{"id":"objective>Civic Education>2014>1","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS","question":"Who among the following could be described as the founding father of Nigerian nationalism?","images":[],"options":{"A":"Nnamdi Azikwe","B":"Herbert Macauley","C":"Ahmadu Bello","D":"Obafemi Awolowo"},"answer":"B","explanation":"Olayinka Herbert Samuel Macauley (14 November 1864 - 7 may 1946) was a Nigerian nationalist and musician and is considered by many Nigerians as the founder/father of Nigerian nationalism.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>2","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW","question":"Rule of law means","images":[],"options":{"A":"Supremacy of the law","B":"Absence of legal immunity","C":"Peace, order and stability","D":"Obedience to any authority"},"answer":"A","explanation":"Rule of law mean Supremacy of the law or constitution over and above everybody or citizens. It was propounded by A. V. Dicey in 1885.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>3","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : QUALITIES/CHARACTERISTICS OF CIVIL SOCIETY; I.E. ACCOUNTABILITY, FAIRNESS, JUSTICE, EQUITY ETC","question":"A major characteristic of civil society is","images":[],"options":{"A":"the desire to win election","B":"corporate responsibility","C":"social responsibility","D":"political gerrymandering"},"answer":"C","explanation":"Social responsibility is an ethical framework and suggests that an entity, be it an organization or individual, has an obligation to act for the benefit of society at large.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>4","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS","question":"Use the diagram below to answer this question      The marked pedestrian crossing shown in the diagram is","images":["data:image/png;base64,"],"options":{"A":"neon sign crossing","B":"amber crossing","C":"cobra crossing","D":"zebra crossing"},"answer":"D","explanation":"The marked pedestrian crossing showing is zebra crossing.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>5","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS","question":"Use the diagram below to answer this question    In the above diagram, all vehicles stopped  mainly  because","images":["data:image/png;base64,"],"options":{"A":"it is emergency crossing line","B":"the pedestrians have already stepped on the line","C":"the traffic wardens have instructed them to stop","D":"the traffic light has shown green"},"answer":"B","explanation":"Vehicle stopped mainly because the pedestrians have already stepped on the line as shown in the diagram.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>6","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP","question":"Citizenship status is acquired through","images":[],"options":{"A":"birth, indigenization, colonization and referendum","B":"association, convention, naturalization and incorporation","C":"birth, naturalization, honorary and registration","D":"registration, inter-relationship, integration and declaration"},"answer":"C","explanation":"Citizenship status can be acquired through several means, including birth, naturalization, honorary and registration. Birth refers to being born within a country's territory or to its citizens. Naturalization is the process by which a foreign citizen becomes a citizen of another country. Honorary citizenship is granted by a country to a foreign individual in recognition of their contributions or services. Registration can refer to the process of registering as a citizen, often applicable to those who have a claim to citizenship through descent.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>7","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS","question":"Human Rights are basic natural rights which people enjoy primarily because they are","images":[],"options":{"A":"members of a political party","B":"international citizens","C":"members of a community","D":"human beings"},"answer":"D","explanation":"Human rights are basic natural right which people enjoy primarily because they are human beings. Human rights are rights exercised by human beings.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>8","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS","question":"Interpersonal relationship exists when","images":[],"options":{"A":"citizens pay their taxes regularly to inland revenue service","B":"citizens are politically conscious and participate in voting","C":"there is interaction between persons in a social setting","D":"group share social interest and communal aspiration"},"answer":"C","explanation":"Interpersonal relationship refers to a strong association among individuals working together in the same organization. Individuals working together are likely to develop interpersonal relationships. One of the most important interpersonal relationships is social interaction in a social setting.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>9","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : MEANING AND ORIGIN OF CULTISM","question":"Cultism can be described to be","images":[],"options":{"A":"amiable","B":"attractive","C":"dangerous","D":"harmless"},"answer":"C","explanation":"Cultism is a social vice that involves a group of people who share a common belief and are involved in secret practices. These practices are often harmful and dangerous to both members of the cult and non-members. Therefore, cultism can be described as dangerous.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>10","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Use the statements below to answer this question   NEWS:  'Rival cult Group Killed Ten on Campus'     STUDENT:  I will definitely need a bullet proof vest before I can go back to the Campus.    Based on the statement above, the decision of the student on having a bullet proof vest shows that cultism","images":[],"options":{"A":"spreads fear and terror.","B":"is a training ground for armed forces.","C":"breed courageous graduates.","D":"propagates self-defence."},"answer":"A","explanation":"The decision of the student on having a bullet proof vest shows that cultism spreads or create fear and terror on the campus.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>11","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM","question":"Use the statements below to answer this question   NEWS:  'Rival cult Group Killed Ten on Campus'     STUDENT:  I will definitely need a bullet proof vest before I can go back to the Campus.  It could be inferred from the statements above that cultism in schools could lead to","images":[],"options":{"A":"sudden prosperity.","B":"uninterrupted academic calender.","C":"popularly on campus.","D":"untimely death."},"answer":"D","explanation":"The statement 'Rival cult Group Killed Ten on Campus' implies that cultism in schools can lead to violence and death. The student's response further emphasizes the danger, as they feel they would need a bulletproof vest to return to campus. Therefore, the inference that can be drawn from these statements is that cultism in schools could lead to 'untimely death', which is option 4.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>12","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING","question":"Victims of human trafficking are usually compelled to engage in","images":[],"options":{"A":"lucrative employment.","B":"visiting tourist sites.","C":"part-time studies.","D":"forced labour."},"answer":"D","explanation":"Victims of human trafficking are usually compelled to engage in forced labour.  Human trafficking simply means the trade of humans for the purpose of forced labour, sexual slavery or commercial sexual exploitation for the trafficker or others.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>13","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS","question":"One habit which People Living With HIV/AIDS (PLWHAs) must avoid to remain healthy and productive is","images":[],"options":{"A":"regular contact with healthy people","B":"self-pity and self-medication","C":"participation in profitable ventures","D":"pursuit of academic studies"},"answer":"B","explanation":"People living with HIV/AIDS must avoid to remain healthy and productive, they should avoid self pity or self-medication.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>14","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT","question":"Youth empowerment is best described as the","images":[],"options":{"A":"training given individuals for acquiring means of livelihood.","B":"practice of engaging in prospective career.","C":"provision of subsidized meals to the citizen by government.","D":"mobilization of citizens for political rally."},"answer":"A","explanation":"Youth empowerment is described as the training given individuals for acquiring means of livelihood to earn a living.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>15","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"The National Assembly Presidency and Court which are inter-related and interdependent in our democracy constitute the","images":[],"options":{"A":"tiers of government","B":"types of democracy","C":"forms of government","D":"arms of government"},"answer":"D","explanation":"The National Assembly, Presidency, and Court are the three arms of government in a democratic system. The National Assembly (Legislature) makes the laws, the Presidency (Executive) implements the laws, and the Court (Judiciary) interprets the laws. They are inter-related and interdependent, each performing its functions to maintain checks and balances in the system.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>16","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;","question":"A system of government that listens to public opinion and tolerates opposition is","images":[],"options":{"A":"dictatorial regime","B":"capitalist regime","C":"democratic regime","D":"socialist regime"},"answer":"C","explanation":"In democratic regime is a system of government that listens to the view or opinion of the people and tolerates opposition in the country.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>17","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY","question":"A situation where most citizens fail to vote in elections coud be described as political","images":[],"options":{"A":"socialization.","B":"culture.","C":"apathy.","D":"legitimacy."},"answer":"C","explanation":"Political apathy is a situation where most citizens do not show interest in politics or fails to vote during the elections.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>18","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS","question":"The division of Nigeria into various constituencies with each electing a person to represent it in the National Assembly is a demonstration of","images":[],"options":{"A":"checks and balances.","B":"popular participation.","C":"political rivalry among the constituents.","D":"drive towards succession in the country."},"answer":"B","explanation":"The division of Nigeria into various constituencies with each electing a person to represent it in the National assembly is a demonstration of popular participation.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>19","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : MEANING OF PUBLIC SERVICE","question":"In Nigeria, public servants are expected to be","images":[],"options":{"A":"non-partisan.","B":"political.","C":"ambitious.","D":"apolitical."},"answer":"A","explanation":"In Nigeria, public servants are expected to be non-partisan. This means they should not show support for any political party or be involved in political activities. This is to ensure that they serve all citizens equally without any bias or favoritism. Being non-partisan is a key principle of public service, not just in Nigeria, but in many countries around the world.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>20","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE","question":"The principle that public servants cannot be held responsible for their official actions denotes","images":[],"options":{"A":"impartiality","B":"accountability","C":"anonymity","D":"neutrality"},"answer":"C","explanation":"Anonymity is a principle that states that public servants can not be held responsible for their official actions.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>21","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND HISTORICAL BACKGROUND OF THE UNIVERSAL DECLARATION OF HUMAN RIGHTS (UDHR)","question":"Universal Declaration of Human Rights (UDHR) is based on the resolution of the","images":[],"options":{"A":"Human Rights Watch","B":"United Nations Organisation","C":"Amnesty International","D":"League of Nations"},"answer":"B","explanation":"Universal Declaration of Human Rights is based on the resolution of the United Nations Organisation (UNO).","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>22","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY","question":"Use the story below to answer this question   Imoh lived with her parents in Kakuri. They were good citizens who detested all forms of immoral acts. Both at home and in school, Imoh had been taught the virtues and values of a good citizen. However, while in a bus on her way home from school, the conductor forgot to ask her fare. She knew that the right thing to do was to pay even when the conductor had forgotten to collect the fare. She also knew that there were other things she could do with the money if it was not paid, but she did what was expected by informing the conductor and paying the fare.    According to the story, Imoh's parents were","images":[],"options":{"A":"wealthy couple.","B":"prominent politicians.","C":"honest and responsible.","D":"religious fanatics."},"answer":"C","explanation":"From the story, it is clear that Imoh's parents have instilled in her the values of honesty and responsibility. They are described as good citizens who detest all forms of immoral acts. This suggests that they are honest and responsible individuals, not necessarily wealthy, prominent politicians, or religious fanatics.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>23","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION","question":"Use the story below to answer this question   Imoh lived with her parents in Kakuri. They were good citizens who detested all forms of immoral acts. Both at home and in school, Imoh had been taught the virtues and values of a good citizen. However, while in a bus on her way home from school, the conductor forgot to ask her fare. She knew that the right thing to do was to pay even when the conductor had forgotten to collect the fare. She also knew that there were other things she could do with the money if it was not paid, but she did what was expected by informing the conductor and paying the fare.  What value did Imoh demonstrate?","images":[],"options":{"A":"Tolerance.","B":"Confidence.","C":"Fair play.","D":"Honesty."},"answer":"D","explanation":"Imoh demonstrated honesty. Honesty is a virtue that involves being truthful and sincere. In the story, Imoh was honest by informing the conductor about the unpaid fare and paying it, even though the conductor had forgotten to collect it.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>24","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS FOR RESOLVING INTER-COMMUNAL CONFLICTS","question":"Conflicts are better resolved in the society through","images":[],"options":{"A":"tribunal.","B":"litigation.","C":"dialogue.","D":"the court."},"answer":"C","explanation":"Conflicts are better resolved in the society through dialogue. Dialogue is a method of conflict resolution that involves open, honest, and respectful communication between parties involved in a conflict. It allows for understanding, compromise, and peaceful resolution of conflicts. While tribunal, litigation, and court are also methods of conflict resolution, they are often more adversarial and may not lead to the best resolution for all parties involved.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>25","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS","question":"To prevent the spread of HIV/AIDS, people should be encouraged to","images":[],"options":{"A":"avoid casual sexual activities.","B":"marry very early in life.","C":"engage in gainful employment.","D":"pursue high education."},"answer":"A","explanation":"HIV/AIDS is primarily spread through unprotected sexual intercourse with an infected person. Therefore, avoiding casual sexual activities can significantly reduce the risk of contracting or spreading the virus. This does not necessarily mean that people should marry early in life, engage in gainful employment, or pursue higher education. These options may have other benefits, but they do not directly prevent the spread of HIV/AIDS.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>26","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT","question":"The nearest government to the people and an important means of promoting grassroots development is the","images":[],"options":{"A":"state government","B":"unitary government","C":"local government","D":"federal government"},"answer":"C","explanation":"Local government is the nearest government that is close to the grass root people and promote government at grass root.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>27","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;","question":"Democratic governance is usually characterized by","images":[],"options":{"A":"free, fair and credible elections.","B":"buoyant and competitive economy.","C":"accessible employment opportunities.","D":"youth participation in governance."},"answer":"A","explanation":"Democratic governance is characterized by free, fair, and credible elections. This is because democracy is a system of government where citizens exercise power by voting. In a democratic system, the citizens have the right to vote in order to choose their representatives in the government. The process of voting should be free, fair, and credible to ensure that the will of the people is accurately represented.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>28","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY","question":"Political apathy often leads to","images":[],"options":{"A":"low level of participation.","B":"good governance.","C":"political stability.","D":"low literacy level."},"answer":"A","explanation":"Political apathy is when the citizens of a country are not interested or involved in politics and this lead to low level of participation.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>29","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : WAYS OF IMPROVING THE PUBLIC SERVICE","question":"Which of the following is not necessary for public servants to perform effectively?","images":[],"options":{"A":"Acceptance of foreign aid by the government.","B":"Improvement in literacy level of the citizens.","C":"Declaration of state of emergency by government.","D":"Periodic review of the constitution by government."},"answer":"A","explanation":"The effectiveness of public servants is not directly influenced by the acceptance of foreign aid by the government. Public servants' performance is more related to their skills, training, resources, and the institutional framework within which they operate. Acceptance of foreign aid by the government is a policy decision that may indirectly affect public service by providing additional resources or imposing certain conditions, but it is not a necessary condition for public servants to perform effectively.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>30","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS","question":"One of the conditions which can limit the enjoyment of Human Rights in Nigeria is the","images":[],"options":{"A":"acceptance of foreign aid by the government.","B":"improvement in literacy level of the citizens.","C":"declaration of state of emergency by government.","D":"periodic review of the constitution by government."},"answer":"C","explanation":"The declaration of a state of emergency by the government can limit the enjoyment of human rights. During a state of emergency, certain civil liberties can be suspended, such as freedom of assembly, freedom of movement, and the right to a fair trial. This is done to maintain order and security during a crisis. Therefore, the declaration of a state of emergency is a condition that can limit the enjoyment of human rights in Nigeria.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>31","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS~~NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS","question":"The drunkard as depicted in the picture will not likely perform his parental role because","images":["data:image/png;base64,"],"options":{"A":"his action constitutes bad influence.","B":"rehabilitation facilities are not available.","C":"drinking problem is associated with the poor.","D":"he has a large family to cater for."},"answer":"A","explanation":"The drunkard as depicted in the picture will not likely perform his parental role because his action constitutes bad influence.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>32","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"The above picture portrays drunkenness mainly as","images":["data:image/png;base64,"],"options":{"A":"an individual habit in the society.","B":"a potential health hazard.","C":"a challenge to responsible parenting.","D":"an environmental nuisance."},"answer":"D","explanation":"The picture portrays drunkenness mainly as an environmental nuisance.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>33","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS","question":"The implication of positive communal relationships is that it","images":[],"options":{"A":"promotes solidarity and love.","B":"ensures obedience to constituted authority.","C":"encourages ethnic diversity.","D":"promotes rural-urban drift."},"answer":"A","explanation":"Positive communal relationships promotes solidarity and love. It also promote diplomatic relationships among the people.","marks":"1","difficulty":"1"},{"id":"objective>Civic Education>2014>34","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING","question":"One major factor that attracts some Nigerians into human trafficking is","images":[],"options":{"A":"over-population related issues.","B":"influx of foreigners into the country.","C":"insatiable quest for quick wealth.","D":"influence of Western and social media."},"answer":"C","explanation":"The major factor that attracts some Nigerians into human trafficking is insatiable quest for quick wealth.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>35","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS","question":"One of the reasons most HIV/AIDS patients are reluctant to disclose their status is because of","images":[],"options":{"A":"the incurable nature of the ailment.","B":"fear of social stigmatization.","C":"lack of sufficient public awareness.","D":"shortage of health counselors."},"answer":"B","explanation":"Fear of social stigmatization is one of the reasons most HIV/AIDS patients are reluctant to disclose their status.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>36","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF RULE OF LAW","question":"Use the report below to answer this question.   The Bawali High Court has ordered the police in Area Z Command to produce Mr. Zeb, who is in police custody for an alleged offence. The court insists that Mr. Zeb cannot be punished until he is found guilty of breach of any law of the land by a court of competent jurisdiction.    The position of the court on this matter justifies the essence of the","images":[],"options":{"A":"rule of law.","B":"legislature.","C":"police command.","D":"separation of powers."},"answer":"A","explanation":"The position of the Court on this matter justifies the essence of the rule of law. A person or an accused person is presume innocent until it is found guilty by the court of law.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>37","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : HOW LEADERS CAN PROTECT THE INTERESTS OF THEIR FOLLOWERS","question":"Leaders can best protect the interest of their followers by","images":[],"options":{"A":"embarking on periodic constitutional review.","B":"creating socio-economic opportunities for foreigners.","C":"creating conducive atmosphere for participation.","D":"rewarding supports with contracts."},"answer":"C","explanation":"Creating Conducive atmosphere for participation is one of the way a leader can protect the interest of their followers.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>38","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS","question":"The most popular means through which citizens of a country can participate in politics is by","images":[],"options":{"A":"being members of political parties.","B":"engaging in constructive criticisms.","C":"engaging in political debates.","D":"voting in elections."},"answer":"D","explanation":"Voting in elections is one of the ways a citizen of a country participate in politics. Citizens participate in politics by exercising his franchise right.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>39","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : FUNCTIONS/NEED FOR CIVIL SOCIETY","question":"Civil societies are vital for the promotion of popular participation because they are","images":[],"options":{"A":"profit-oriented organizations.","B":"engaged in developmental programmes.","C":"involved in political education.","D":"formidable oppositions to government."},"answer":"C","explanation":"Civil societies are non-profit organizations that are involved in promoting political education among the citizens. They are not profit-oriented organizations, they are not necessarily engaged in developmental programmes, and they are not formidable oppositions to government. They are involved in political education because they help to educate the citizens about their rights, responsibilities, and the workings of the government. This helps to promote popular participation in the political process as more informed citizens are more likely to participate actively in the political process.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>40","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.    From this dialogue, it is very likely that Wanja will be exhibiting the following characters except","images":[],"options":{"A":"disobedience to constituted authority.","B":"truancy and perpetual lateness to school.","C":"hospitable attitude towards people.","D":"arrogance and unruly behavior."},"answer":"C","explanation":"From this dialogue, it is very likely that Wanja will not exhibit the character of hospitable attitude towards people.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>41","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  Which of the following may result from Wanja's habit?","images":[],"options":{"A":"Humility for elders.","B":"Criminality in the society.","C":"Advocacy for hard drugs by NGOs.","D":"Excellent performance in school."},"answer":"B","explanation":"Criminality in the society may result from Wanja's habit smoking and alcohols result in bad friends and this lead to criminality in the society.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>42","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : SYMPTOMS OF DRUG ABUSE","question":"Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  From Ada's admonition, it could be deduced that taking hard drugs could","images":[],"options":{"A":"make people respect the addicts.","B":"lead to insanity of the addicts.","C":"make people to adore the drug addicts.","D":"ensure courteous behavior by the addicts."},"answer":"B","explanation":"From Ada's admonition, it could be deduced that taking hard drugs could lead to insanity of the addicts.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>43","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE","question":"Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  From the above dialogue, Wanja's behavior could be curtailed by","images":[],"options":{"A":"Sending him abroad for further studies.","B":"Financial inducement.","C":"Re-orientation and rehabilitation.","D":"Indulging him with expensive gifts."},"answer":"C","explanation":"From the dialogue, Wanja is involved in substance abuse and this behavior can be curtailed through re-orientation and rehabilitation. Re-orientation involves changing his perspective about substance abuse and its effects, while rehabilitation involves helping him overcome his addiction. Sending him abroad for further studies or indulging him with expensive gifts may not necessarily change his behavior. Financial inducement may even worsen the situation as he may use the money to buy more drugs.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>44","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES","question":"Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  Which of the following governmental agencies is the most capable of controlling the activities of Wanja and his group?","images":[],"options":{"A":"National Agency for Food and Drug Administration and Control (NAFDAC)","B":"National Orientation Agency (NOA)","C":"National Emergency Management Agency (NEMA)","D":"National Drug Law Enforcement Agency (NDLEA)"},"answer":"D","explanation":"National Drug Law Enforcement Agency (NDLEA) is governmental agencies that is capable of controlling the activities of Wanja and his group. NDLEA are charge with the responsibility of orientate the drug addicts.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>45","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC","question":"Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  One of the major barriers to national development is the","images":[],"options":{"A":"low poverty level.","B":"existence of multi-party system.","C":"prevalence of corrupt practices.","D":"persistent rural-urban migration."},"answer":"C","explanation":"The dialogue suggests that drug and alcohol abuse, which can be seen as a form of social corruption, is a major barrier to national development.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>46","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS","question":"Use the dialogue below to answer this question   Ada: Wanja, where are you going to in this ungodly hour of the night?  Wanja: I am heading towards my usual joint to enjoy myself.  Ada: Which joint?  Wanja: XYZ Night Club, where I take marijuana and alcoholic beverages, I really want to be high tonight so that when people see me tomorrow, they will fear and respect me.  Ada: Remember, people who work under the influence of hard drugs and alcoholic beverages are prone to either psychiatric problems or premature death. Softly young man, imbibe good-natured character, you have the world at your feet and a destiny to fulfill. Pray you will not be the architect of your own misfortune.  The quotation above shows that the speaker is concerned about","images":[],"options":{"A":"nationalism.","B":"revolution.","C":"tourism.","D":"welfarism."},"answer":"D","explanation":"The dialogue shows that Ada is concerned about Wanja's welfare, which is why she warns him about the dangers of drug and alcohol abuse and advises him to lead a good life.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>47","subject":"Civic Education","year":"2014","type":"Objective","topic":"EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : IMPORTANCE AND BENEFITS OF YOUTH EMPOWERMENT SKILLS","question":"A major benefit of youth empowerment is","images":[],"options":{"A":"dependence on foreign aid.","B":"discouragement of patriotism.","C":"reduction in crime rate.","D":"negation to national prosperity."},"answer":"C","explanation":"Reduction in crime rate is a major benefit of Youth empowerment. It is believed that when youths are engaged the crime rate reduced.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>48","subject":"Civic Education","year":"2014","type":"Objective","topic":"GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC","question":"Use the story below to answer this question.   Chief Bilisi was prominent politician and honourable minister in Kantogo Republic. He had sponsored several candidates to power and made them to swear oath of aliegiance to him. In return, they awarded contracts and offered financial and material assistance to him at the expense of the public. This had resulted in the non-provision of social amenities. These were some of the grieviances the community had against him for which a mob gathered in front of his house shouting and hauling abusive words at him. They did not stop at that as they vandalized property and obstructed vehicular movement.    When leaders like Chief Bilisi place self interest above public goods, the result is that","images":[],"options":{"A":"rebellion becomes inevitable.","B":"cooperation of citizens is guaranteed.","C":"international support for the regime is ensured.","D":".society becomes more peaceful and orderly."},"answer":"A","explanation":"When leaders like Chief Bilisi place self interest above public goods, the result is that rebellion becomes inevitable.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>49","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : DEFINITION OF LAW AND ORDER","question":"Use the story below to answer this question.   Chief Bilisi was prominent politician and honourable minister in Kantogo Republic. He had sponsored several candidates to power and made them to swear oath of aliegiance to him. In return, they awarded contracts and offered financial and material assistance to him at the expense of the public. This had resulted in the non-provision of social amenities. These were some of the grieviances the community had against him for which a mob gathered in front of his house shouting and hauling abusive words at him. They did not stop at that as they vandalized property and obstructed vehicular movement.  The condition of disorderly behaviour exhibited by the mob in the story best describes the","images":[],"options":{"A":"ineffectiveness of the police.","B":"breakdown of law and order.","C":"importance of ministerial position.","D":"need for stiffer security measures."},"answer":"B","explanation":"The condition of disorderly behaviour exhibited by the mob in the story best describes the breakdown of law and order in the society or country.","marks":"1","difficulty":"2"},{"id":"objective>Civic Education>2014>50","subject":"Civic Education","year":"2014","type":"Objective","topic":"NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE OF LAW AND ORDER IN THE SOCIETY","question":"Use the story below to answer this question.   Chief Bilisi was prominent politician and honourable minister in Kantogo Republic. He had sponsored several candidates to power and made them to swear oath of aliegiance to him. In return, they awarded contracts and offered financial and material assistance to him at the expense of the public. This had resulted in the non-provision of social amenities. These were some of the grieviances the community had against him for which a mob gathered in front of his house shouting and hauling abusive words at him. They did not stop at that as they vandalized property and obstructed vehicular movement.  A major lesson Nigerians could learn from the story is that","images":[],"options":{"A":"leaders can empower voters by giving them money.","B":"security officials should use brutal force on citizens.","C":"the underprivileged should not vie for elective positions.","D":"greed and related vices can cause serious breach of the law."},"answer":"D","explanation":"A major lesson Nigerians could learn from the story is that greed and related vices can cause serious breach of the law.","marks":"1","difficulty":"2"}];